/**
 * Chunk outbound text while preferring newline boundaries over spaces.
 * Mirrors the behavior of the SDK's chunkTextForOutbound helper.
 */
export function chunkTextForOutbound(text: string, limit: number): string[] {
  if (text.length <= limit) {
    return [text];
  }
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= limit) {
      chunks.push(remaining);
      break;
    }
    const window = remaining.slice(0, limit);
    const lastNewline = window.lastIndexOf("\n");
    const lastSpace = window.lastIndexOf(" ");
    const breakIdx = lastNewline > 0 ? lastNewline : lastSpace;
    if (breakIdx > 0) {
      chunks.push(remaining.slice(0, breakIdx));
      remaining = remaining.slice(breakIdx + 1).trimStart();
    } else {
      // No suitable break; hard-split at limit.
      chunks.push(window);
      remaining = remaining.slice(limit);
    }
  }
  return chunks;
}

