import type { DmPolicy, GroupPolicy, OpenClawConfig } from "./runtime-api.js";

/**
 * Per-board configuration for a named PulseBoard board (group channel).
 * Boards are identified by their board name (e.g. "general", "ops").
 */
export type PulseBoardBoardConfig = {
  /** If true, the bot only replies when @mentioned. Defaults to true. */
  requireMention?: boolean;
  /** Whether this board is enabled for routing. */
  enabled?: boolean;
  /** Sender allowlist scoped to this board. */
  allowFrom?: Array<string | number>;
  /** Custom system prompt for this board. */
  systemPrompt?: string;
};

/**
 * Account-level PulseBoard configuration.
 * A single account connects to one PulseBoard hub with one token.
 */
export type PulseBoardAccountConfig = {
  /** Human-readable label for this account. */
  name?: string;
  /** Whether this account is enabled. Defaults to true. */
  enabled?: boolean;
  /** WebSocket hub URL (e.g. wss://hub.pulseboard.example.com). */
  hubUrl?: string;
  /** API token used to authenticate with the PulseBoard hub. */
  token?: string;
  /** Path to a file containing the API token (alternative to token). */
  tokenFile?: string;
  /** Bot username as registered on the PulseBoard hub. */
  username?: string;
  /** Direct message access control policy. Default: "pairing". */
  dmPolicy?: DmPolicy;
  /** Allowlist of sender usernames permitted to DM this bot. */
  allowFrom?: Array<string | number>;
  /** Default target to send outbound messages to when none is specified. */
  defaultTo?: string;
  /** Board/group access control policy. Default: "allowlist". */
  groupPolicy?: GroupPolicy;
  /** Allowlist of board names for group policy enforcement. */
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board name. */
  boards?: Record<string, PulseBoardBoardConfig>;
  /** Maximum text chunk size in characters. Default: 4000. */
  textChunkLimit?: number;
  /** Markdown rendering configuration. */
  markdown?: PulseBoardMarkdownConfig;
};

/**
 * Top-level PulseBoard channel config, supporting multiple named accounts.
 */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  /** Named sub-accounts (e.g. for connecting to multiple hubs). */
  accounts?: Record<string, PulseBoardAccountConfig>;
  /** Default account to use when none is specified. */
  defaultAccount?: string;
};

/**
 * Narrow augmentation of the core OpenClaw config type for type safety
 * in PulseBoard-internal code.
 */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/**
 * Represents a message received from the PulseBoard hub.
 */
export type PulseBoardInboundMessage = {
  /** Unique message ID assigned by the hub. */
  messageId: string;
  /**
   * Conversation peer: board name for board messages, sender username for DMs.
   * For boards, this is the normalized board name (e.g. "#general").
   */
  target: string;
  /** Username of the sender. */
  senderUsername: string;
  /** Message body text. */
  text: string;
  /** Unix timestamp (ms). */
  timestamp: number;
  /** Whether this message arrived on a board (group) rather than a DM. */
  isBoard: boolean;
};

/**
 * Result of a PulseBoard connectivity probe.
 */
export type PulseBoardProbe = {
  /** Whether the probe succeeded. */
  ok: boolean;
  /** Human-readable failure reason, if any. */
  reason?: string;
  /** Detailed error message, if any. */
  error?: string;
  /** Hub URL that was probed. */
  hubUrl: string;
  /** Authenticated username, confirmed by the hub on successful connect. */
  username: string;
  /** Round-trip latency in milliseconds, if measured. */
  latencyMs?: number;
};

/**
 * Markdown rendering configuration (mirrors core MarkdownConfig shape).
 */
export type PulseBoardMarkdownConfig = {
  /** How to render markdown tables. */
  tables?: "plain" | "html" | "markdown" | "text" | "disabled";
};

