/**
 * PulseBoard target normalization utilities.
 *
 * PulseBoard uses two target namespaces:
 * - Boards (group channels): "#<board-name>" (e.g. "#general", "#ops")
 * - Direct messages: "@<username>" or just "<username>"
 *
 * Targets may optionally be prefixed with "pulseboard:", "board:", or "user:"
 * for disambiguation.
 */

/** Pattern: board names are "#<alphanumeric-slug>", DM targets are "@<username>" or bare usernames. */
const PULSEBOARD_TARGET_PATTERN = /^[#@]?[\w][\w.-]*$/u;

/** Returns true when the normalized target is a board (group) channel. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/** Returns true when the normalized target is a direct-message user. */
export function isDirectTarget(target: string): boolean {
  return !target.startsWith("#");
}

/**
 * Normalize a raw PulseBoard routing target string.
 *
 * Rules:
 * - "pulseboard:#general" → "#general"
 * - "board:general"       → "#general"
 * - "user:alice"          → "alice"
 * - "@alice"              → "alice"
 * - "#general"            → "#general"
 * - "general"             → "general" (ambiguous; caller should disambiguate)
 *
 * Returns undefined when the input cannot be a valid target.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }

  let target = trimmed;

  // Strip optional "pulseboard:" scheme prefix.
  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // "board:<name>" → "#<name>"
  if (target.toLowerCase().startsWith("board:")) {
    const name = target.slice("board:".length).trim();
    target = name.startsWith("#") ? name : `#${name}`;
  }

  // "user:<name>" → strip the prefix.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
    // Remove leading "@" if present.
    if (target.startsWith("@")) {
      target = target.slice(1);
    }
  }

  // Normalize "@username" → "username" for DMs.
  if (target.startsWith("@") && !target.startsWith("#")) {
    target = target.slice(1);
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Returns true if the string looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Allow "#" prefix for boards; bare alphanumeric slugs for users.
  const testable = trimmed.startsWith("#") ? trimmed.slice(1) : trimmed;
  return PULSEBOARD_TARGET_PATTERN.test(trimmed) && testable.length > 0;
}

/**
 * Normalize an allowlist entry to a canonical form.
 * Strips scheme prefixes and lowercases the result.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

/**
 * Build the set of allowlist candidates for a given sender username.
 * Returns lowercase strings suitable for matching against the allowlist.
 */
export function buildPulseBoardAllowlistCandidates(senderUsername: string): string[] {
  const lower = senderUsername.trim().toLowerCase();
  if (!lower) {
    return [];
  }
  return [lower];
}

/**
 * Check whether a sender is present in an allowlist.
 * Returns the source of the match if found.
 */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: Array<string | number>;
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const allowFromSet = new Set(
    params.allowFrom
      .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
      .filter(Boolean),
  );
  if (allowFromSet.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseBoardAllowlistCandidates(params.senderUsername);
  for (const candidate of candidates) {
    if (allowFromSet.has(candidate)) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

