import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

/**
 * Probe PulseBoard connectivity for a given account.
 *
 * Performs a lightweight HTTP check against the PulseBoard hub's health
 * endpoint using the configured token. Returns a structured probe result.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  params: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: params.accountId });
  const timeoutMs = params.timeoutMs ?? 8000;

  if (!account.configured) {
    return {
      ok: false,
      reason: "not configured",
      error: "PulseBoard account is missing hubUrl, username, or token.",
      hubUrl: account.hubUrl || "(unset)",
      username: account.username || "(unset)",
    };
  }

  // Convert ws:// / wss:// scheme to http:// / https:// for the REST probe.
  const httpBase = account.hubUrl
    .replace(/^wss:\/\//i, "https://")
    .replace(/^ws:\/\//i, "http://");
  const healthUrl = `${httpBase.replace(/\/$/, "")}/api/health`;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  const start = Date.now();
  try {
    const response = await fetch(healthUrl, {
      method: "GET",
      headers: {
        Authorization: `Bearer ${account.token}`,
        "X-PulseBoard-Username": account.username,
      },
      signal: controller.signal,
    });
    clearTimeout(timer);

    const latencyMs = Date.now() - start;
    if (!response.ok) {
      return {
        ok: false,
        reason: `HTTP ${response.status}`,
        error: `PulseBoard hub returned HTTP ${response.status}.`,
        hubUrl: account.hubUrl,
        username: account.username,
        latencyMs,
      };
    }

    return {
      ok: true,
      hubUrl: account.hubUrl,
      username: account.username,
      latencyMs,
    };
  } catch (err) {
    clearTimeout(timer);
    const error = err instanceof Error ? err.message : String(err);
    return {
      ok: false,
      reason: controller.signal.aborted ? "timeout" : "connection error",
      error,
      hubUrl: account.hubUrl,
      username: account.username,
      latencyMs: Date.now() - start,
    };
  }
}

