/**
 * PulseBoard WebSocket client.
 *
 * Manages a WebSocket connection to a PulseBoard hub. Handles authentication,
 * board subscriptions, message dispatch, and graceful shutdown.
 *
 * The PulseBoard wire protocol uses newline-delimited JSON frames:
 *   {"type":"auth","token":"...","username":"..."}
 *   {"type":"subscribe","boards":["general","ops"]}
 *   {"type":"message","target":"#general","text":"hello"}
 *   {"type":"dm","to":"alice","text":"hi"}
 *
 * Inbound frames from the hub:
 *   {"type":"message","id":"...","from":"alice","target":"#general","text":"...","ts":...}
 *   {"type":"dm","id":"...","from":"alice","text":"...","ts":...}
 *   {"type":"ack","id":"..."}
 *   {"type":"error","message":"..."}
 */

import type { PulseBoardInboundMessage } from "./types.js";

export type PulseBoardClientOptions = {
  hubUrl: string;
  token: string;
  username: string;
  /** Boards to subscribe to on connect. */
  boards?: string[];
  /** Called for each inbound message (DM or board). */
  onMessage?: (msg: PulseBoardInboundMessage) => Promise<void>;
  /** Called when the connection is closed (by remote or locally). */
  onClose?: (reason?: string) => void;
  /** Called when an error occurs. */
  onError?: (err: Error) => void;
  /** Logger interface (matches PluginLogger). */
  log?: { info(msg: string): void; warn(msg: string): void; error(msg: string): void };
};

export type PulseBoardClient = {
  /** Send a text message to a board ("#name") or user ("username"). */
  send(target: string, text: string): Promise<string>;
  /** Returns true if the WebSocket is open and authenticated. */
  isReady(): boolean;
  /** Gracefully close the connection. */
  close(reason?: string): void;
};

let _messageCounter = 0;

function nextMessageId(): string {
  _messageCounter = (_messageCounter + 1) % 1_000_000;
  return `pb-${Date.now()}-${_messageCounter}`;
}

/**
 * Connect to a PulseBoard hub and return a live client handle.
 *
 * Note: In this bundled extension the WebSocket constructor is the global
 * `WebSocket` available in Node 22+. The function resolves once the
 * authentication handshake completes.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  return new Promise((resolve, reject) => {
    let ready = false;
    const pendingAcks = new Map<string, (ok: boolean) => void>();

    // Node 22 ships global WebSocket; the `ws` package is not required.
    const ws = new WebSocket(opts.hubUrl);

    ws.addEventListener("error", (event) => {
      const err = new Error(`PulseBoard WebSocket error: ${String(event)}`);
      opts.onError?.(err);
      if (!ready) {
        reject(err);
      }
    });

    ws.addEventListener("close", (event) => {
      ready = false;
      opts.onClose?.(event.reason ?? undefined);
    });

    ws.addEventListener("open", () => {
      // Authenticate immediately after connect.
      ws.send(
        JSON.stringify({
          type: "auth",
          token: opts.token,
          username: opts.username,
        }),
      );
    });

    ws.addEventListener("message", (event) => {
      let frame: Record<string, unknown>;
      try {
        frame = JSON.parse(String(event.data)) as Record<string, unknown>;
      } catch {
        opts.log?.warn("[pulseboard] received non-JSON frame; ignoring");
        return;
      }

      switch (frame.type) {
        case "auth_ok": {
          // Subscribe to configured boards after successful auth.
          if (opts.boards && opts.boards.length > 0) {
            const names = opts.boards.map((b) =>
              b.startsWith("#") ? b.slice(1) : b,
            );
            ws.send(JSON.stringify({ type: "subscribe", boards: names }));
          }
          ready = true;
          resolve(client);
          break;
        }

        case "auth_error": {
          const err = new Error(
            `PulseBoard authentication failed: ${String(frame.message ?? "unknown")}`,
          );
          opts.onError?.(err);
          if (!ready) {
            reject(err);
          }
          break;
        }

        case "ack": {
          const id = String(frame.id ?? "");
          pendingAcks.get(id)?.(true);
          pendingAcks.delete(id);
          break;
        }

        case "error": {
          const errMsg = String(frame.message ?? "hub error");
          opts.log?.warn(`[pulseboard] hub error: ${errMsg}`);
          const id = typeof frame.id === "string" ? frame.id : null;
          if (id) {
            pendingAcks.get(id)?.(false);
            pendingAcks.delete(id);
          }
          break;
        }

        case "message": {
          // Board/group message.
          const boardName = String(frame.target ?? "");
          const target = boardName.startsWith("#") ? boardName : `#${boardName}`;
          const msg: PulseBoardInboundMessage = {
            messageId: String(frame.id ?? nextMessageId()),
            target,
            senderUsername: String(frame.from ?? ""),
            text: String(frame.text ?? ""),
            timestamp: typeof frame.ts === "number" ? frame.ts : Date.now(),
            isBoard: true,
          };
          opts.onMessage?.(msg).catch((err: unknown) => {
            opts.log?.error(
              `[pulseboard] inbound message handler error: ${err instanceof Error ? err.message : String(err)}`,
            );
          });
          break;
        }

        case "dm": {
          // Direct message.
          const sender = String(frame.from ?? "");
          const msg: PulseBoardInboundMessage = {
            messageId: String(frame.id ?? nextMessageId()),
            target: sender,
            senderUsername: sender,
            text: String(frame.text ?? ""),
            timestamp: typeof frame.ts === "number" ? frame.ts : Date.now(),
            isBoard: false,
          };
          opts.onMessage?.(msg).catch((err: unknown) => {
            opts.log?.error(
              `[pulseboard] inbound DM handler error: ${err instanceof Error ? err.message : String(err)}`,
            );
          });
          break;
        }

        default:
          // Ignore unknown frame types for forward compatibility.
          break;
      }
    });

    const client: PulseBoardClient = {
      isReady: () => ready,

      send: (target: string, text: string): Promise<string> => {
        if (!ready) {
          return Promise.reject(new Error("PulseBoard client is not ready"));
        }
        const id = nextMessageId();
        const frame = target.startsWith("#")
          ? { type: "message", id, target, text }
          : { type: "dm", id, to: target, text };
        return new Promise((res, rej) => {
          pendingAcks.set(id, (ok) => {
            if (ok) {
              res(id);
            } else {
              rej(new Error(`PulseBoard send failed for message ${id}`));
            }
          });
          ws.send(JSON.stringify(frame));
          // Resolve optimistically after 5 s if no ack arrives (hub may not ack).
          setTimeout(() => {
            if (pendingAcks.has(id)) {
              pendingAcks.delete(id);
              res(id);
            }
          }, 5000);
        });
      },

      close: (reason?: string) => {
        ready = false;
        try {
          ws.close(1000, reason ?? "shutdown");
        } catch {
          // Ignore close errors.
        }
      },
    };
  });
}

