import { resolvePulseBoardAccount } from "./accounts.js";
import { connectPulseBoardClient } from "./client.js";
import type { PulseBoardClient } from "./client.js";
import { normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  /** A live client to use instead of opening a transient connection. */
  client?: PulseBoardClient;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string): string {
  const normalized = normalizePulseBoardMessagingTarget(to);
  if (!normalized) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }
  return normalized;
}

/**
 * Send a text message to a PulseBoard board ("#board-name") or user ("username").
 *
 * If a live `client` is provided in `opts`, it is used directly. Otherwise a
 * transient connection is established and torn down after sending.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need hubUrl, username, and token in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to);
  const payload = text.trim();

  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends.");
  }

  let messageId: string;
  if (opts.client?.isReady()) {
    messageId = await opts.client.send(target, payload);
  } else {
    // Open a transient connection for one-off sends (e.g. pairing notifications).
    const transient = await connectPulseBoardClient({
      hubUrl: account.hubUrl,
      token: account.token,
      username: account.username,
    });
    try {
      messageId = await transient.send(target, payload);
    } finally {
      transient.close("sent");
    }
  }

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId, target };
}

