import type { ResolvedPulseBoardAccount } from "./accounts.js";
import { connectPulseBoardClient } from "./client.js";
import type { PulseBoardClient } from "./client.js";
import type { CoreConfig } from "./types.js";

/**
 * Parameters passed to the provider monitor.
 * Mirrors the pattern used by IRC's monitorIrcProvider.
 */
export type PulseBoardMonitorParams = {
  accountId: string;
  config: CoreConfig;
  account: ResolvedPulseBoardAccount;
  abortSignal: AbortSignal;
  /** Called for each inbound message; dispatches to OpenClaw routing. */
  onMessage: (params: {
    accountId: string;
    target: string;
    senderUsername: string;
    text: string;
    messageId: string;
    isBoard: boolean;
  }) => Promise<void>;
  /** Called to record status updates. */
  statusSink: {
    setRunning(running: boolean): void;
    setError(error: string | null): void;
    setLastInboundAt(ts: number): void;
    setLastOutboundAt(ts: number): void;
  };
  log?: { info(msg: string): void; warn(msg: string): void; error(msg: string): void };
};

export type PulseBoardMonitor = {
  stop: () => void;
};

/**
 * Start the PulseBoard account monitor.
 *
 * Opens a WebSocket connection to the hub and processes inbound messages
 * until the abortSignal fires or the connection closes permanently.
 */
export async function monitorPulseBoardProvider(
  params: PulseBoardMonitorParams,
): Promise<PulseBoardMonitor> {
  const { account, abortSignal, statusSink, log } = params;

  let client: PulseBoardClient | null = null;

  const boards = account.config.boards
    ? Object.keys(account.config.boards).map((b) => (b.startsWith("#") ? b.slice(1) : b))
    : [];

  try {
    client = await connectPulseBoardClient({
      hubUrl: account.hubUrl,
      token: account.token,
      username: account.username,
      boards,
      onMessage: async (msg) => {
        statusSink.setLastInboundAt(msg.timestamp);
        try {
          await params.onMessage({
            accountId: params.accountId,
            target: msg.target,
            senderUsername: msg.senderUsername,
            text: msg.text,
            messageId: msg.messageId,
            isBoard: msg.isBoard,
          });
        } catch (err) {
          log?.error(
            `[pulseboard:${params.accountId}] inbound dispatch error: ${err instanceof Error ? err.message : String(err)}`,
          );
        }
      },
      onClose: (reason) => {
        statusSink.setRunning(false);
        log?.info(`[pulseboard:${params.accountId}] connection closed: ${reason ?? "unknown"}`);
      },
      onError: (err) => {
        statusSink.setError(err.message);
        log?.error(`[pulseboard:${params.accountId}] connection error: ${err.message}`);
      },
      log,
    });
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    statusSink.setError(message);
    statusSink.setRunning(false);
    throw err;
  }

  statusSink.setRunning(true);
  statusSink.setError(null);
  log?.info(
    `[pulseboard:${params.accountId}] connected to ${account.hubUrl} as ${account.username}`,
  );

  // Wait until the abort signal fires, then shut down.
  const stopPromise = new Promise<void>((resolve) => {
    abortSignal.addEventListener("abort", () => {
      resolve();
    });
  });

  // Return a handle that the caller can use to stop the monitor early.
  const monitor: PulseBoardMonitor = {
    stop: () => {
      client?.close("gateway shutdown");
      statusSink.setRunning(false);
    },
  };

  // Resolve the Promise returned to runStoppablePassiveMonitor only after stop.
  stopPromise.then(() => {
    monitor.stop();
  });

  return monitor;
}

