import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import type { DmPolicy } from "openclaw/plugin-sdk/setup";
import { normalizeAccountId } from "openclaw/plugin-sdk/routing";
import {
  applyAccountNameToChannelSection,
  createSetupInputPresenceValidator,
  createTopLevelChannelAllowFromSetter,
  createTopLevelChannelDmPolicySetter,
  patchScopedAccountConfig,
} from "openclaw/plugin-sdk/setup";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

const channel = "pulseboard" as const;

const setPulseBoardTopLevelDmPolicy = createTopLevelChannelDmPolicySetter({ channel });
const setPulseBoardTopLevelAllowFrom = createTopLevelChannelAllowFromSetter({ channel });

export function updatePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  patch: Partial<PulseBoardAccountConfig>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: channel,
    accountId,
    patch,
    ensureChannelEnabled: false,
    ensureAccountEnabled: false,
  }) as CoreConfig;
}

export function setPulseBoardDmPolicy(cfg: CoreConfig, dmPolicy: DmPolicy): CoreConfig {
  return setPulseBoardTopLevelDmPolicy(cfg, dmPolicy) as CoreConfig;
}

export function setPulseBoardAllowFrom(cfg: CoreConfig, allowFrom: string[]): CoreConfig {
  return setPulseBoardTopLevelAllowFrom(cfg, allowFrom) as CoreConfig;
}

export function setPulseBoardBoardAccess(
  cfg: CoreConfig,
  accountId: string,
  policy: "open" | "allowlist" | "disabled",
  boardNames: string[],
  normalizeBoard: (raw: string) => string | null,
): CoreConfig {
  if (policy !== "allowlist") {
    return updatePulseBoardAccountConfig(cfg, accountId, { enabled: true, groupPolicy: policy });
  }
  const normalizedBoards = [
    ...new Set(boardNames.map((b) => normalizeBoard(b)).filter(Boolean)),
  ];
  const boards = Object.fromEntries(normalizedBoards.map((b) => [b, {}]));
  return updatePulseBoardAccountConfig(cfg, accountId, {
    enabled: true,
    groupPolicy: "allowlist",
    boards,
  });
}

type PulseBoardSetupInput = {
  name?: string;
  hubUrl?: string;
  token?: string;
  username?: string;
};

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
  applyAccountName: ({ cfg, accountId, name }) =>
    applyAccountNameToChannelSection({ cfg, channelKey: channel, accountId, name }),
  validateInput: createSetupInputPresenceValidator({
    whenNotUseEnv: [
      { someOf: ["hubUrl"], message: "PulseBoard requires hubUrl." },
      { someOf: ["username"], message: "PulseBoard requires username." },
      { someOf: ["token"], message: "PulseBoard requires token." },
    ],
  }),
  applyAccountConfig: ({ cfg, accountId, input }) => {
    const setupInput = input as PulseBoardSetupInput;
    const namedConfig = applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name: setupInput.name,
    });
    const patch: Partial<PulseBoardAccountConfig> = {
      enabled: true,
      hubUrl: setupInput.hubUrl?.trim(),
      token: setupInput.token?.trim(),
      username: setupInput.username?.trim(),
    };
    return patchScopedAccountConfig({
      cfg: namedConfig,
      channelKey: channel,
      accountId,
      patch,
    }) as CoreConfig;
  },
};

