    expect(chunks.join("").replace(/\s/g, "")).toBe(text);
  });

  it("respects 4000-char limit (PulseBoard platform max)", () => {
    const long = "a".repeat(10000);
    const chunks = chunkTextForOutbound(long, PULSEBOARD_DEFAULT_CHUNK_LIMIT);
    expect(chunks.every((c) => c.length <= PULSEBOARD_DEFAULT_CHUNK_LIMIT)).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// resolvePulseBoardAccount
// ---------------------------------------------------------------------------

describe("resolvePulseBoardAccount", () => {
  const baseConfig: CoreConfig = {
    channels: {
      pulseboard: {
        hubUrl: "wss://hub.example.com",
        username: "mybot",
