    expect(account.configured).toBe(true);
    expect(account.hubUrl).toBe("wss://hub.example.com");
    expect(account.username).toBe("mybot");
    expect(account.token).toBe("pb_tok_test123");
    expect(account.tokenSource).toBe("config");
  });

  it("applies default chunk limit", () => {
